import { InputBase } from '@/components/atoms/Input/base/input';
import { InputGroup } from '@/components/atoms/Input/base/input-group';
import { NativeSelect } from '@/vendor/untitled-ui/base/select/select-native';
import { WithDataId } from '@/types/withDataId';
import {
  FieldWrapper,
  FieldWrapperProps,
} from '@/components/molecules/FieldWrapper/FieldWrapper';

export type InputPhoneNumberFieldProps = Omit<
  React.ComponentPropsWithoutRef<typeof InputBase>,
  'className'
> & {
  countries?: { label: string; value: string }[];
} & WithDataId &
  Omit<FieldWrapperProps, 'children'>;

export function InputPhoneNumberField({
  type: _type,
  placeholder,
  shortcut,
  countries = [{ label: 'US', value: 'US' }],
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  ...restProps
}: InputPhoneNumberFieldProps) {
  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
    >
      <InputGroup
        leadingAddon={
          <NativeSelect
            options={countries}
            defaultValue="US"
          />
        }
        {...restProps}
      >
        <InputBase
          type="tel"
          inputMode="tel"
          placeholder={placeholder}
          shortcut={shortcut}
          isInvalid={isInvalid}
        />
      </InputGroup>
    </FieldWrapper>
  );
}
