import { InputBase } from '@/components/atoms/Input/base/input';
import { InputGroup } from '@/components/atoms/Input/base/input-group';
import { NativeSelect } from '@/vendor/untitled-ui/base/select/select-native';
import { WithDataId } from '@/types/withDataId';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { FieldWrapperProps } from '@/components/molecules/FieldWrapper/FieldWrapper';

export type InputAmountFieldProps = Omit<
  React.ComponentPropsWithoutRef<typeof InputBase>,
  'className'
> & {
  currencies?: { label: string; value: string }[];
} & WithDataId &
  Omit<FieldWrapperProps, 'children'>;

export function InputAmountField({
  placeholder,
  shortcut,
  currencies = [{ value: 'USD', label: 'USD' }],
  'data-id': dataId,
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  ...restProps
}: InputAmountFieldProps) {
  return (
    <FieldWrapper
      id={id}
      label={label}
      hint={hint}
      isInvalid={isInvalid}
      isRequired={isRequired}
      tooltip={tooltip}
      description={description}
      fieldSize={fieldSize}
      labelPosition={labelPosition}
    >
      <InputGroup
        trailingAddon={
          <NativeSelect
            options={currencies}
            defaultValue="USD"
          />
        }
        {...restProps}
      >
        <InputBase
          placeholder={placeholder}
          shortcut={shortcut}
          data-id={dataId}
          isInvalid={isInvalid}
        />
      </InputGroup>
    </FieldWrapper>
  );
}
